import json
import re

# Access the query results using the storage keys
# First, let's load all the records from package_database
# to find MIT-licensed release packages

package_records = var_functions.query_db:5  # All package records from initial query

# Find MIT-licensed release packages
mit_release_packages = []

for record in package_records:
    if record['System'] == 'NPM':
        # Check license MIT
        licenses_str = record['Licenses']
        try:
            licenses = json.loads(licenses_str)
            if 'MIT' in licenses:
                # Check IsRelease
                version_info_str = record['VersionInfo']
                try:
                    version_info = json.loads(version_info_str)
                    if version_info.get('IsRelease', False) == True:
                        mit_release_packages.append({
                            'System': record['System'],
                            'Name': record['Name'],
                            'Version': record['Version'],
                            'Licenses': licenses
                        })
                except:
                    pass  # Skip if JSON parsing fails
        except:
            # If direct parse fails, check with simpler pattern
            if '"MIT"' in licenses_str or '\"MIT\"' in licenses_str:
                version_info_str = record['VersionInfo']
                if '"IsRelease": true' in version_info_str.lower():
                    mit_release_packages.append({
                        'System': record['System'],
                        'Name': record['Name'],
                        'Version': record['Version'],
                        'Licenses': ['MIT']  # assumption
                    })

print('Found', len(mit_release_packages), 'MIT-licensed release packages')
if mit_release_packages:
    print('Sample packages:', json.dumps(mit_release_packages[:10], indent=2))
else:
    print('No packages found, trying alternative approach')

# Create a mapping of these packages for lookup
package_key_map = {}
for p in mit_release_packages:
    key = (p['System'], p['Name'], p['Version'])
    package_key_map[key] = p

